// ---------------------------------------------------------------
// WheelTuning
// ---------------------------------------------------------------
/// Spring / friction tuning parameters for a vehicle wheel.
///
/// Used when adding a wheel via
/// :meth:`DynamicRayCastVehicleController.add_wheel`.
///
/// .. note::
///    :meth:`default` returns rapier's upstream defaults which are
///    typically *too soft* for most real-world setups — wheels tend
///    to bottom out and drift sideways. Expect to tighten
///    ``suspension_stiffness``, ``friction_slip``, and
///    ``side_friction_stiffness`` substantially.
#[pyclass(name = "WheelTuning", module = "rapier")]
#[derive(Debug, Clone, Copy)]
pub struct WheelTuning(pub rapier::control::WheelTuning);

#[pymethods]
impl WheelTuning {
    /// Build a ``WheelTuning`` with optional overrides.
    ///
    /// :param suspension_stiffness: Spring constant.
    /// :param suspension_compression: Compression damping.
    /// :param suspension_damping: Relaxation damping.
    /// :param max_suspension_travel: Max compression travel.
    /// :param side_friction_stiffness: Lateral tire grip.
    /// :param friction_slip: Longitudinal friction coefficient.
    /// :param max_suspension_force: Force cap on the spring.
    #[new]
    #[pyo3(signature = (suspension_stiffness=None, suspension_compression=None, suspension_damping=None, max_suspension_travel=None, side_friction_stiffness=None, friction_slip=None, max_suspension_force=None))]
    #[allow(clippy::too_many_arguments)]
    fn new(
        suspension_stiffness: Option<Real>,
        suspension_compression: Option<Real>,
        suspension_damping: Option<Real>,
        max_suspension_travel: Option<Real>,
        side_friction_stiffness: Option<Real>,
        friction_slip: Option<Real>,
        max_suspension_force: Option<Real>,
    ) -> Self {
        let mut t = rapier::control::WheelTuning::default();
        if let Some(v) = suspension_stiffness {
            t.suspension_stiffness = v;
        }
        if let Some(v) = suspension_compression {
            t.suspension_compression = v;
        }
        if let Some(v) = suspension_damping {
            t.suspension_damping = v;
        }
        if let Some(v) = max_suspension_travel {
            t.max_suspension_travel = v;
        }
        if let Some(v) = side_friction_stiffness {
            t.side_friction_stiffness = v;
        }
        if let Some(v) = friction_slip {
            t.friction_slip = v;
        }
        if let Some(v) = max_suspension_force {
            t.max_suspension_force = v;
        }
        Self(t)
    }

    /// Return rapier's default ``WheelTuning``.
    ///
    /// Beware — the upstream defaults are intentionally soft and
    /// often produce skating / bottoming-out behavior. Tune for
    /// your vehicle.
    #[staticmethod]
    fn default() -> Self {
        Self(rapier::control::WheelTuning::default())
    }

    /// Spring stiffness constant.
    #[getter]
    fn suspension_stiffness(&self) -> Real {
        self.0.suspension_stiffness
    }
    #[setter]
    /// Assign the suspension spring stiffness constant.
    fn set_suspension_stiffness(&mut self, v: Real) {
        self.0.suspension_stiffness = v;
    }
    /// Damping while the spring is compressing.
    #[getter]
    fn suspension_compression(&self) -> Real {
        self.0.suspension_compression
    }
    #[setter]
    /// Assign the compression-phase damping coefficient.
    fn set_suspension_compression(&mut self, v: Real) {
        self.0.suspension_compression = v;
    }
    /// Damping while the spring is relaxing.
    #[getter]
    fn suspension_damping(&self) -> Real {
        self.0.suspension_damping
    }
    #[setter]
    /// Assign the relaxation-phase damping coefficient.
    fn set_suspension_damping(&mut self, v: Real) {
        self.0.suspension_damping = v;
    }
    /// Max travel distance for the suspension.
    #[getter]
    fn max_suspension_travel(&self) -> Real {
        self.0.max_suspension_travel
    }
    #[setter]
    /// Assign the maximum suspension travel distance.
    fn set_max_suspension_travel(&mut self, v: Real) {
        self.0.max_suspension_travel = v;
    }
    /// Lateral (sideways) tire stiffness.
    #[getter]
    fn side_friction_stiffness(&self) -> Real {
        self.0.side_friction_stiffness
    }
    #[setter]
    /// Assign the lateral tire stiffness coefficient.
    fn set_side_friction_stiffness(&mut self, v: Real) {
        self.0.side_friction_stiffness = v;
    }
    /// Longitudinal friction coefficient.
    #[getter]
    fn friction_slip(&self) -> Real {
        self.0.friction_slip
    }
    #[setter]
    /// Assign the longitudinal friction coefficient.
    fn set_friction_slip(&mut self, v: Real) {
        self.0.friction_slip = v;
    }
    /// Maximum suspension spring force.
    #[getter]
    fn max_suspension_force(&self) -> Real {
        self.0.max_suspension_force
    }
    #[setter]
    /// Assign the cap on suspension spring force.
    fn set_max_suspension_force(&mut self, v: Real) {
        self.0.max_suspension_force = v;
    }

    /// Return the ``WheelTuning(...)`` repr.
    fn __repr__(&self) -> String {
        format!(
            "WheelTuning(suspension_stiffness={}, friction_slip={})",
            self.0.suspension_stiffness, self.0.friction_slip
        )
    }
}

// ---------------------------------------------------------------
// RayCastInfo
// ---------------------------------------------------------------
/// Read-only per-wheel raycast hit info for the vehicle controller.
///
/// Snapshot taken after the latest
/// :meth:`DynamicRayCastVehicleController.update_vehicle` call.
///
/// :ivar contact_normal_ws: World-space normal at the contact.
/// :ivar contact_point_ws: World-space contact point.
/// :ivar suspension_length: Current spring length (compressed).
/// :ivar hard_point_ws: World-space wheel attachment point on chassis.
/// :ivar is_in_contact: ``True`` if the ray hit anything.
/// :ivar ground_object: Hit collider handle, if any.
#[pyclass(name = "RayCastInfo", module = "rapier", frozen)]
#[derive(Debug, Clone, Copy)]
pub struct RayCastInfo {
    #[pyo3(get)]
    pub contact_normal_ws: Vec3,
    #[pyo3(get)]
    pub contact_point_ws: Vec3,
    #[pyo3(get)]
    pub suspension_length: Real,
    #[pyo3(get)]
    pub hard_point_ws: Vec3,
    #[pyo3(get)]
    pub is_in_contact: bool,
    #[pyo3(get)]
    pub ground_object: Option<ColliderHandle>,
}

#[pymethods]
impl RayCastInfo {
    /// Return the ``RayCastInfo(...)`` repr.
    fn __repr__(&self) -> String {
        format!(
            "RayCastInfo(is_in_contact={}, suspension_length={})",
            self.is_in_contact, self.suspension_length
        )
    }
}

impl RayCastInfo {
    #[inline]
    fn from_wheel(w: &rapier::control::Wheel) -> Self {
        let r = w.raycast_info();
        let cn: crate::na::Vector3<Real> = r.contact_normal_ws.into();
        let cp: crate::na::Vector3<Real> = r.contact_point_ws.into();
        let hp: crate::na::Vector3<Real> = r.hard_point_ws.into();
        Self {
            contact_normal_ws: Vec3(cn),
            contact_point_ws: Vec3(cp),
            suspension_length: r.suspension_length,
            hard_point_ws: Vec3(hp),
            is_in_contact: r.is_in_contact,
            ground_object: r.ground_object.map(ColliderHandle),
        }
    }
}

// ---------------------------------------------------------------
// Wheel — a snapshot/proxy. The upstream controller owns the
// backing `Vec<Wheel>`; we project read+write fields into a Python
// class. Mutations on a `Wheel` instance returned by
// `.wheels()` / `.wheel(i)` do NOT propagate back to the
// controller — they are detached copies. Use the controller's
// `set_brake` / `set_steering` / `apply_engine_force` for
// mutations that need to take effect.
// ---------------------------------------------------------------
/// Detached snapshot of one vehicle wheel.
///
/// .. warning::
///    Instances returned by
///    :meth:`DynamicRayCastVehicleController.wheels` /
///    :meth:`DynamicRayCastVehicleController.wheel` are **copies**.
///    Mutating the fields here does **not** propagate back to the
///    controller. Use
///    :meth:`DynamicRayCastVehicleController.set_brake`,
///    :meth:`set_steering`, and :meth:`apply_engine_force` to
///    actually drive the wheel.
#[pyclass(name = "Wheel", module = "rapier")]
#[derive(Debug, Clone, Copy)]
pub struct Wheel {
    #[pyo3(get, set)]
    pub chassis_connection_point_cs: Vec3,
    #[pyo3(get, set)]
    pub direction_cs: Vec3,
    #[pyo3(get, set)]
    pub axle_cs: Vec3,
    #[pyo3(get, set)]
    pub suspension_rest_length: Real,
    #[pyo3(get, set)]
    pub max_suspension_travel: Real,
    #[pyo3(get, set)]
    pub radius: Real,
    #[pyo3(get, set)]
    pub suspension_stiffness: Real,
    #[pyo3(get, set)]
    pub damping_compression: Real,
    #[pyo3(get, set)]
    pub damping_relaxation: Real,
    #[pyo3(get, set)]
    pub friction_slip: Real,
    #[pyo3(get, set)]
    pub side_friction_stiffness: Real,
    #[pyo3(get, set)]
    pub rotation: Real,
    #[pyo3(get, set)]
    pub max_suspension_force: Real,
    #[pyo3(get, set)]
    pub forward_impulse: Real,
    #[pyo3(get, set)]
    pub side_impulse: Real,
    #[pyo3(get, set)]
    pub steering: Real,
    #[pyo3(get, set)]
    pub engine_force: Real,
    #[pyo3(get, set)]
    pub brake: Real,
    #[pyo3(get, set)]
    pub wheel_suspension_force: Real,
    #[pyo3(get)]
    pub raycast_info: RayCastInfo,
}

#[pymethods]
impl Wheel {
    /// Return the ``Wheel(...)`` repr.
    fn __repr__(&self) -> String {
        format!(
            "Wheel(engine_force={}, brake={}, steering={})",
            self.engine_force, self.brake, self.steering
        )
    }
}

impl Wheel {
    #[inline]
    pub(crate) fn from_rapier(w: &rapier::control::Wheel) -> Self {
        let ccp: crate::na::Vector3<Real> = w.chassis_connection_point_cs.into();
        let dir: crate::na::Vector3<Real> = w.direction_cs.into();
        let axle: crate::na::Vector3<Real> = w.axle_cs.into();
        Self {
            chassis_connection_point_cs: Vec3(ccp),
            direction_cs: Vec3(dir),
            axle_cs: Vec3(axle),
            suspension_rest_length: w.suspension_rest_length,
            max_suspension_travel: w.max_suspension_travel,
            radius: w.radius,
            suspension_stiffness: w.suspension_stiffness,
            damping_compression: w.damping_compression,
            damping_relaxation: w.damping_relaxation,
            friction_slip: w.friction_slip,
            side_friction_stiffness: w.side_friction_stiffness,
            rotation: w.rotation,
            max_suspension_force: w.max_suspension_force,
            forward_impulse: w.forward_impulse,
            side_impulse: w.side_impulse,
            steering: w.steering,
            engine_force: w.engine_force,
            brake: w.brake,
            wheel_suspension_force: w.wheel_suspension_force,
            raycast_info: RayCastInfo::from_wheel(w),
        }
    }
}

// ---------------------------------------------------------------
// DynamicRayCastVehicleController
// ---------------------------------------------------------------
/// Raycast-based vehicle controller attached to a chassis body (3D only).
///
/// Each "wheel" is a raycast from a chassis-space attachment point
/// along ``direction_cs`` for ``suspension_rest_length`` units. The
/// controller resolves spring/damper forces from each ray hit and
/// applies them to the chassis :class:`RigidBody` to simulate a
/// driving vehicle without needing actual wheel colliders.
#[pyclass(name = "DynamicRayCastVehicleController", module = "rapier")]
pub struct DynamicRayCastVehicleController(pub rapier::control::DynamicRayCastVehicleController);

#[pymethods]
impl DynamicRayCastVehicleController {
    /// Construct a vehicle controller for the given chassis body.
    ///
    /// :param chassis_handle: :class:`RigidBodyHandle` of the chassis
    ///     dynamic body.
    #[new]
    fn new(chassis_handle: &RigidBodyHandle) -> Self {
        Self(rapier::control::DynamicRayCastVehicleController::new(
            chassis_handle.0,
        ))
    }

    /// Append a new wheel to this controller.
    ///
    /// :param chassis_connection_cs: Wheel attachment point in
    ///     chassis-local coordinates.
    /// :param direction_cs: Suspension axis (typically ``-up``).
    /// :param axle_cs: Wheel spin axis in chassis-local coords.
    /// :param suspension_rest_length: Spring rest length.
    /// :param radius: Wheel radius (for raycast clipping).
    /// :param tuning: :class:`WheelTuning` spring/friction params.
    /// :returns: The index of the new wheel.
    #[pyo3(signature = (chassis_connection_cs, direction_cs, axle_cs, suspension_rest_length, radius, tuning))]
    #[allow(clippy::too_many_arguments)]
    fn add_wheel(
        &mut self,
        chassis_connection_cs: PyVector,
        direction_cs: PyVector,
        axle_cs: PyVector,
        suspension_rest_length: Real,
        radius: Real,
        tuning: &WheelTuning,
    ) -> usize {
        let ccs: rapier::math::Vector = chassis_connection_cs.0.into();
        let dir: rapier::math::Vector = direction_cs.0.into();
        let axl: rapier::math::Vector = axle_cs.0.into();
        self.0
            .add_wheel(ccs, dir, axl, suspension_rest_length, radius, &tuning.0);
        self.0.wheels().len() - 1
    }

    /// Step the vehicle controller for one tick.
    ///
    /// Performs per-wheel raycasts through ``queries`` and updates
    /// the chassis :class:`RigidBody` with the resulting forces and
    /// torques. Call this before stepping the physics world.
    ///
    /// Requires a fresh :class:`QueryPipeline` — typically call
    /// ``world.update_query_pipeline()`` first.
    ///
    /// :param dt: Time step in seconds.
    /// :param bodies: Rigid-body set (mutated).
    /// :param colliders: Collider set (mutated).
    /// :param queries: Up-to-date :class:`QueryPipeline`.
    /// :param filter: Optional query filter.
    #[pyo3(signature = (dt, bodies, colliders, queries, filter=None))]
    fn update_vehicle(
        &mut self,
        py: Python<'_>,
        dt: Real,
        bodies: Py<RigidBodySet>,
        colliders: Py<ColliderSet>,
        queries: &QueryPipeline,
        filter: Option<&QueryFilter>,
    ) -> PyResult<()> {
        let bp = queries.broad_phase.borrow(py);
        let np = queries.narrow_phase.borrow(py);
        let mut bodies_ref = bodies.borrow_mut(py);
        let mut colliders_ref = colliders.borrow_mut(py);
        let qf = filter.map(|f| f.as_rapier(None)).unwrap_or_default();
        let qpmut = bp.0.as_query_pipeline_mut(
            np.0.query_dispatcher(),
            &mut bodies_ref.0,
            &mut colliders_ref.0,
            qf,
        );
        self.0.update_vehicle(dt, qpmut);
        Ok(())
    }

    /// Set the brake force on wheel ``idx``.
    ///
    /// :raises TypeError: if ``idx`` is out of range.
    fn set_brake(&mut self, idx: usize, brake: Real) -> PyResult<()> {
        let wheels = self.0.wheels_mut();
        if idx >= wheels.len() {
            return Err(PyTypeError::new_err(format!(
                "wheel index {} out of range (len={})",
                idx,
                wheels.len()
            )));
        }
        wheels[idx].brake = brake;
        Ok(())
    }

    /// Set the steering angle (radians) on wheel ``idx``.
    ///
    /// :raises TypeError: if ``idx`` is out of range.
    fn set_steering(&mut self, idx: usize, steering: Real) -> PyResult<()> {
        let wheels = self.0.wheels_mut();
        if idx >= wheels.len() {
            return Err(PyTypeError::new_err(format!(
                "wheel index {} out of range (len={})",
                idx,
                wheels.len()
            )));
        }
        wheels[idx].steering = steering;
        Ok(())
    }

    /// Set the engine drive force on wheel ``idx``.
    ///
    /// :raises TypeError: if ``idx`` is out of range.
    fn apply_engine_force(&mut self, idx: usize, force: Real) -> PyResult<()> {
        let wheels = self.0.wheels_mut();
        if idx >= wheels.len() {
            return Err(PyTypeError::new_err(format!(
                "wheel index {} out of range (len={})",
                idx,
                wheels.len()
            )));
        }
        wheels[idx].engine_force = force;
        Ok(())
    }

    /// Return a fresh list of :class:`Wheel` snapshots (detached copies).
    fn wheels(&self) -> Vec<Wheel> {
        self.0.wheels().iter().map(Wheel::from_rapier).collect()
    }

    /// Return a snapshot of the single wheel at ``idx``.
    ///
    /// :raises TypeError: if ``idx`` is out of range.
    fn wheel(&self, idx: usize) -> PyResult<Wheel> {
        let wheels = self.0.wheels();
        wheels.get(idx).map(Wheel::from_rapier).ok_or_else(|| {
            PyTypeError::new_err(format!(
                "wheel index {} out of range (len={})",
                idx,
                wheels.len()
            ))
        })
    }

    /// Current forward speed in km/h.
    fn current_speed_km_hour(&self) -> Real {
        // upstream's `current_vehicle_speed` is in m/s; convert to km/h.
        self.0.current_vehicle_speed * (3.6 as Real)
    }

    /// Current forward speed in m/s along the chassis forward axis.
    #[getter]
    fn current_vehicle_speed(&self) -> Real {
        self.0.current_vehicle_speed
    }

    /// :class:`RigidBodyHandle` of the chassis body.
    fn chassis(&self) -> RigidBodyHandle {
        RigidBodyHandle(self.0.chassis)
    }

    /// Index of the up-axis in chassis-local coords (``0=X``, ``1=Y``, ``2=Z``).
    #[getter]
    fn index_up_axis(&self) -> usize {
        self.0.index_up_axis
    }
    #[setter]
    /// Set the chassis-local up-axis index (``0=X``, ``1=Y``, ``2=Z``).
    fn set_index_up_axis(&mut self, v: usize) {
        self.0.index_up_axis = v;
    }
    /// Index of the forward-axis in chassis-local coords (``0=X``, ``1=Y``, ``2=Z``).
    #[getter]
    fn index_forward_axis(&self) -> usize {
        self.0.index_forward_axis
    }
    #[setter]
    /// Set the chassis-local forward-axis index (``0=X``, ``1=Y``, ``2=Z``).
    fn set_index_forward_axis(&mut self, v: usize) {
        self.0.index_forward_axis = v;
    }

    /// Return a debug string with the wheel count and forward speed.
    fn __repr__(&self) -> String {
        format!(
            "DynamicRayCastVehicleController(wheels={}, speed={} m/s)",
            self.0.wheels().len(),
            self.0.current_vehicle_speed
        )
    }
}

// ============================================================================
// Registration.
// ============================================================================

pub fn register_controllers(
    _py: crate::pyo3::Python<'_>,
    m: &crate::pyo3::Bound<'_, crate::pyo3::types::PyModule>,
) -> crate::pyo3::PyResult<()> {
    use crate::pyo3::prelude::*;
    m.add_class::<CharacterLength>()?;
    m.add_class::<CharacterAutostep>()?;
    m.add_class::<EffectiveCharacterMovement>()?;
    m.add_class::<CharacterCollision>()?;
    m.add_class::<KinematicCharacterController>()?;
    m.add_class::<AxesMask>()?;
    m.add_class::<PdErrors>()?;
    m.add_class::<PidCorrection>()?;
    m.add_class::<PdController>()?;
    m.add_class::<PidController>()?;
    m.add_class::<WheelTuning>()?;
    m.add_class::<RayCastInfo>()?;
    m.add_class::<Wheel>()?;
    m.add_class::<DynamicRayCastVehicleController>()?;
    Ok(())
}
